import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十五章 先赢眼前一剑","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md","filePath":"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十五章-先赢眼前一剑" tabindex="-1">第十五章 先赢眼前一剑 <a class="header-anchor" href="#第十五章-先赢眼前一剑" aria-label="Permalink to &quot;第十五章 先赢眼前一剑&quot;">​</a></h1><p>陈玄在药堂住了二十三日。</p><p>最初三日，他只能趴着。</p><p>背后钩伤每日清创两次，右肋以木片固定，脚腕敷消肿药。十五年回脉草排掉了血煞，清创时仍从伤口里取出两片细碎砂石。医师说，若这些东西留在肉里，外面结痂再快，入夏后也会从里面烂开。</p><p>陈玄第一次真正明白，“逃出来”与“伤好了”之间隔着多少工序。</p><p>第四日，刑律峰来问话。</p><p>不是把他带去问刑堂。两名弟子坐在药床外，一人问，一人记，医师全程在旁。问到背伤渗血，医师便停；问到血煞与回脉草，刑律弟子将时间、药龄、剂量各换一种顺序问了三遍。</p><p>陈玄如实说山洞、暗河、分段催药和两名搜山者。</p><p>唯独掌天瓶被拿掉。</p><p>十五年回脉草解释为父亲《山药札记》所记暗河药点。刑律峰已派人按图复核，洞中确有一株根须完整的老药，湿土里也留着取叶痕迹。药草为何恰在生死时出现，仍可疑，却没有第二条证据指向一只月下凝液的小瓶。</p><p>“你为何不连根带走？”问话弟子道。</p><p>“伤重，带不活；整株来历更难解释。”</p><p>“你现在倒承认知道它难解释。”</p><p>“知道。”陈玄道，“若只带两片叶，宗门要查还能回洞查根。整株挖走，便只剩我的话。”</p><p>记录弟子抬头看了他一眼，将这句也写下。</p><p>刑律峰没有当场判定全信，也没有因此扣押他。问话结束，复核仍会继续。陈玄对此并不意外。一个杂役独自带回魔修证据，又恰好靠一株十五年药排煞，若无人查才不正常。</p><p>第七日，他能自己坐起。</p><p>韩执事带来任务结算：查明朱榜异状十五贡献，带回阵物与位置十贡献，促成两名失散队员获救另记十贡献。猎杀獠熊没有完成，三十贡献与回灵丹不发。</p><p>“共三十五。”韩执事道，“不是六十，也没有藏经阁二层。宗门按做成的事算。”</p><p>“应当如此。”</p><p>“另有一枚正式外门腰牌。”</p><p>新腰牌正面刻青云外门，背面是陈玄姓名，不再有试役或杂役字样。岁试前十六、炼气五层、黑风山任务履历三项合计，够他从药园杂役转入正式外门。</p><p>陈玄接过，没有立刻收起：“药园差事是否要停？”</p><p>“可以停。正式弟子每月两块灵石、一瓶养气散，另有两日讲堂。”</p><p>“我想继续接圃。”</p><p>韩执事看了他一眼：“舍不得那柄旧药锄？”</p><p>“药园能学辨药，也有灵田练引水术。只是不再占杂役定额，按贡献接病圃。”</p><p>“随你。”韩执事把结算册放到床头，“丁字园缺的从来不是想来的人，是肯把坏根挖明白的人。”</p><p>第九日，陈玄去了内伤堂。</p><p>他走得很慢，腰背不能直转，手里也没有拄剑，只用一根药堂木杖。</p><p>郑衡住在东侧静室。</p><p>雷符近身引爆震伤心脉，他说话仍不能太长，床边却已经摆了三只拆开的阵盘。见陈玄进门，他先指了指桌上空掉的药碗，让他等自己把最后一口喝完。</p><p>“断牌。”郑衡开口。</p><p>陈玄把半块郑字牌放在桌上。</p><p>郑衡从枕下取出另一半。两处断口合在一起，木纹严丝合缝，中间灵线却已经烧断。</p><p>“我拆牌续敛气阵，原以为这辈子找不回来。”</p><p>“在阵边捡到的。”</p><p>“不是捡牌。”郑衡看着他，“我是说命。”</p><p>陈玄没有说彼此彼此。</p><p>那会把三个人在阵里不同的选择说成一笔正好抵消的账。郑衡的雷符争来三息，陈玄的地图带回救援，各自都是真的，不必非要算到谁欠谁。</p><p>“心脉如何？”他问。</p><p>“能保。三个月内不能画雷符，以后也不能在胸前引爆。”郑衡把两半木牌收进小匣，“阵房给我换一个新牌，旧的我不扔。不是留着提醒自己英勇，是提醒自己下一次别把唯一退路阵钉全押在一处。”</p><p>他没有因死里逃生忽然变得无所畏惧。</p><p>活下来只让他更具体地知道，哪一步应当改。</p><p>陆炳在西侧。</p><p>左腿保住了，膝下却还没有知觉。医师在床尾挂了沙袋，让他每日用脚背抬三十次。陈玄进去时，沙袋刚离地一寸便落下。</p><p>陆炳额上全是汗，第一句话却是：“王道全来找过我。”</p><p>“要消息钱？”</p><p>“半块灵石，分三人，一人十六灵钱有余。他把零头也算得清。”</p><p>陈玄从钱袋取出十七枚灵钱放在床边。</p><p>陆炳看着那堆钱：“你替郑衡也付？”</p><p>“只付我的。”</p><p>“还算你没乱讲义气。”陆炳靠回枕上，“我若这条腿好不了，内门预选便没了。接朱榜时我说差二十四贡献，现在倒差得更远。”</p><p>陈玄没有用“以后还有机会”安慰。</p><p>陆炳比他更知道外门参选年限和伤势意味着什么。</p><p>“你后悔接任务？”</p><p>“后悔。”陆炳答得很快，“早知道是血阵，三十贡献给三百我也不去。可进了阵之后，斩腿线、走北坡都没错。后悔接，不等于后面每一步都后悔。”</p><p>他看向陈玄背后厚厚敷料：“你呢？”</p><p>“也后悔。”</p><p>“后悔什么？”</p><p>“发现遮气阵粉时，撤得还不够早。应该先把警讯符送出去，再取样。”</p><p>陆炳笑了一下，牵到肩伤，又疼得吸气：“行。至少咱们三个都没把活下来吹成天意。”</p><p>离开内伤堂前，陆炳让陈玄把那柄厚背刀拿去修器房。</p><p>刀口在血阵里崩了三处，刀背仍完整。</p><p>“修理钱记我的账。”</p><p>“你还用得上？”</p><p>陆炳看着没有知觉的左腿：“先修。腿能不能站，是医师的事；刀留不留下，是我的事。”</p><p>陈玄提走了刀。</p><p>第二十三日，他离开药堂。</p><p>鲁老头在丁字药园门口等着，手里那杆烟还是没点。见陈玄能自己走，只哼了一声，将门后的旧药锄踢过来。</p><p>“阴坡寒髓草新叶生斑，你若手还认得锄，自己去看。”</p><p>“医师说半月内不能弯腰太久。”</p><p>“那便蹲一会儿，站一会儿。谁让你拿命干？”</p><p>药园没有因他带回血阵证据便停下。</p><p>沟渠仍会堵，药虫仍会在叶背产卵，三号寒髓草新叶的白斑也不是象征，而是寒玉粉铺得过密，根部透气不足。陈玄不能挥锄，便让年轻杂役松土，自己在旁记录。</p><p>午后，鲁老头端来一罐药粥。</p><p>两人坐在田埂吃。老人不问血魔子，也不问刑律峰，只说陆炳的刀送去修要三块灵石，修器房那个姓陶的手艺好，脾气坏，讲价时别先说刀主在病床上。</p><p>这些寻常话让陈玄真正意识到自己回来了。</p><p>不是从暗河上岸那一刻，也不是跨过山门那一刻。</p><p>是仍有人同他计较三块灵石的修刀钱，仍有一株药要查根，明日还得按时凝水。</p><p>伤后第一个月，陈玄没有拔剑。</p><p>白日只做不牵背伤的轻活，夜里运行最缓周天。每次灵力经过肩井，他都会停一息，分辨是清创后的皮肉痛，还是经脉本身的滞涩。医师开的养脉丹三日一枚，不因有一瓶便每日吞服。</p><p>掌天瓶在月圆仍凝一滴绿液。</p><p>这滴液体被他用来催熟一株从坊市买来的六年续脉藤。十年药龄时，他停下催长，只取两片藤叶配入热敷药包。绿液催的是藤，真正落到经脉上的，仍是药性、剂量与一个月没有强行出剑的克制。</p><p>第三十日，胸口骨裂不再疼。</p><p>第三十七日，青锋剑第一次出鞘。</p><p>陈玄没有练六十剑，只做十次空手定势、十次不凝锋直刺。第一剑右臂发紧，第六剑才恢复原来轨迹。第二十剑结束，他收剑，不以“尚有余力”为由加练。</p><p>第二个月，练剑恢复到每日四十。</p><p>第三个月，才回到六十。</p><p>那一月末，郑衡已经能下床走路。他没有再用雷符，改练以土木阵钉缓冲冲击；陆炳左脚恢复痛觉，第一次抬起沙袋半尺，疼得把床栏掰出一道裂纹。</p><p>谁都没有回到受伤前。</p><p>也没有停在伤床那日。</p><p>陈玄的炼气五层则在这样的日子里慢慢填实。没有生死耗空后的突然反弹，也没有十五年回脉草余药帮他推关。养气散仍三日一小份，四属灵气仍按旧次序入丹田。</p><p>黑风山归来第五个月，气旋触到六层关隘。</p><p>陈玄又等了十二日。</p><p>等到右肩连续十日无滞涩，等六十剑在移动靶下能成五十六，等医师复查确认背伤只剩皮肉紧绷，他才服半份养气散。</p><p>破境用了七个周天。</p><p>木水先入，金火后归。气旋扩大时，肩后旧伤发热，却没有裂痛。陈玄没有在灵力上涨的瞬间出剑，只继续调息到天亮。</p><p>炼气六层。</p><p>第二日，他以半力斩出青元剑芒。</p><p>离刃三尺半，比五层时多一尺有余。全力能够到五尺，消耗仍接近两成。境界提升让剑更远，没有让每一剑忽然不需代价。</p><p>韩执事验过修为，将一张内门预选告示放在桌上。</p><p>选拔在六个月后。</p><p>参选条件为炼气六层以上，或近两年有重大任务功绩；前十转入内门，前三可在主殿接受各峰长老面见。告示下另列一行：因黑风山任务复核延期，本届不以朱榜退队记录扣减评绩。</p><p>这是制度修补真正落到一个普通弟子身上的样子。</p><p>若仍按旧例，陈玄三人未完成猎熊，任务评绩会留“未竟”；如今调查认定血阵改变任务本质，退队与示警不再算怯战。</p><p>陈玄把名字写进报名册。</p><p>接下来六个月，他没有把全部日子都变成备赛。</p><p>药园接圃照旧，初五石桥对练照旧，每月给王道全的药量也没有因正式外门俸禄增加。两块月例灵石中，一块存作伤药，一块用于修器、符纸与讲堂。那柄青锋剑在黑风山没有折，却被血索磨损阵纹，修复花去两块半灵石。</p><p>王小虎也在第四个月踏入炼气六层，拿到参选资格。</p><p>两人在石桥第一次用灵力对练时，王小虎的基础十三式比岁试时稳了许多。他不再每见剑尖便闭眼，第三十招甚至抓住陈玄换气，木剑点中右肋。</p><p>陈玄停剑：“这一招你赢。”</p><p>“只一招？”</p><p>“整场还没完。”</p><p>“你这人连夸都要按招算。”</p><p>王小虎嘴上抱怨，眼里却有笑。他没有因陈玄先到六层便把自己放回小时候那个跟在后面的人，也没有把“兄弟”当作上台后该让半剑的理由。</p><p>“大比若抽到你，”王小虎道，“我不收。”</p><p>“我也不收。”</p><p>“打伤药钱各付各的。”</p><p>“学得很快。”</p><p>第五个月末，王道全送来参选名单。</p><p>叶承，炼气九层，火枪；秦岚，炼气九层，水火术；沈渊，炼气八层中期，长枪；韩牧，炼气七层巅峰，厚土盾。每个人名后都有近三场记录、常用法器与消息可信等级。</p><p>“先看谁？”王道全问。</p><p>陈玄没有先翻叶承。</p><p>名单第一页是刘嵩，炼气七层，九环刀，本届第一轮最可能抽中的十六人之一。</p><p>“先看同组。”</p><p>“你的目标不是前三？”</p><p>“目标在后面，第一场在眼前。”</p><p>王道全摇扇：“这句话若写在盘口边，兴许能抬你两成赔率。”</p><p>“不卖。”</p><p>“小气。”</p><p>选拔前一个月，陈玄的炼气六层已至后期。</p><p>他没有冲七层。</p><p>从六层到七层只过五个多月，气旋虽满，经脉积累仍差一层。若用整滴绿液催出高龄聚气花，再以药浴硬推，或许能赶在大比前跨过去；可绿液只能催药，药力造成的虚浮与暗伤仍由身体承担。</p><p>陈玄放弃这个打算。</p><p>以六层参选，第一轮便可能遇七层。</p><p>这不是最有利的状态，却是他真实走到的位置。</p><p>最后七日，他反而把每日六十剑减到三十。十五剑固定凝锋，十剑移动，最后五剑由王小虎临时点靶。剩余时间用来睡足、养脉与整理对手记录。</p><p>大比前夜，王道全提着食盒来药园。</p><p>两荤一素，一壶米酒，三张护身符，两包回灵散。东西逐样写在账上，只有最下面一行“送行酒”没有价格。</p><p>“我押你进前十，六块灵石。”王道全说，“不算多。”</p><p>“上次七块。”</p><p>“所以这次少一块。”</p><p>“赔率？”</p><p>“一赔五。外面都说你在黑风山吓破了胆，伤好后境界也只到六层。”</p><p>陈玄端起半碗酒：“前半句，他们没说错。”</p><p>王道全扇子停了一下：“怕？”</p><p>“怕再进血阵，怕同伴出不来，也怕旧伤再裂。”陈玄喝了一口，“怕不妨碍上台。”</p><p>“明日若第一轮输了？”</p><p>“回来种药，还储物袋的账。”</p><p>“你总算记得。”王道全给自己倒酒，“那若赢？”</p><p>陈玄看向桌边青锋剑。</p><p>六层对七层，不是没有胜算。后面还有八层、九层，也有真正不靠半拍失误便能把他压回白线的人。</p><p>这些名字都在名单上。</p><p>今晚想得再远，也不会替他挡住明早第一刀。</p><p>“先赢眼前一剑。”他说。</p><p>窗外，演武峰正在试钟。</p><p>一声清响越过药田，惊动寒髓草叶上凝着的水珠。水珠沿白色旧裂纹滑到叶尖，没有落下。</p><p>陈玄将剩下半碗酒放回桌上。</p><p>不再喝了。</p><p>（第十五章完）</p>',161)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
